+function coerce(value: string): string | number | boolean {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (value.trim() !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:e[-+]?\\d+)?$/i.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const separator = line.indexOf("=");
+    if (separator < 1) throw new Error("Expected a key=value pair.");
+    const key = camelCase(line.slice(0, separator).trim());
+    let value = line.slice(separator + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) throw new Error("Unterminated quoted value.");
+      value = value.slice(1, -1);
+    }
+    result[key] = coerce(value);
+  }
+  return result;
+}
