function fileName(name: string, format: string): string {
  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
}

export async function loadConfig(
  options: ConfigOptions,
): Promise<LoadedConfig> {
  const paths = options.searchPaths?.length ? options.searchPaths : ["."];
  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
  let configPath: string | undefined;
  const values: Record<string, unknown> = {};

  for (const directory of paths) {
    let found: string | undefined;
    for (const format of formats) {
      const candidate = `${directory}/${fileName(options.name, format)}`;
      if (await exists(candidate)) {
        found = candidate;
        break;
      }
    }
    if (!found) continue;
    const resolvedPath = await resolve(found);
    let parsed: unknown;
    try {
      const content = await readFile(found);
      parsed = options.parser
        ? options.parser(content)
        : found.endsWith(".rc")
        ? parseRc(content)
        : JSON.parse(content);
      if (!isPlainObject(parsed)) {
        throw new Error("Configuration must be a plain object.");
      }
    } catch (error) {
      throw new ConfigParseError(resolvedPath, error);
    }
    configPath ??= resolvedPath;
    const flattened = flatten(parsed as Record<string, unknown>);
    for (const [key, value] of Object.entries(flattened)) {
      if (!(key in values)) values[key] = value;
    }
    if (!options.mergeConfigs) break;
  }
  return { path: configPath, values };
}

